using System.Security.Claims;
using Microsoft.AspNetCore.Http.HttpResults;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker;

public static class ShipmentEndpoints
{
    public static void MapShipmentApi(this WebApplication app)
    {
        var api = app.MapGroup("/api/shipments").RequireAuthorization();

        // Dispatchers: get all shipments with optional filters
        api.MapGet("/", async (
            ApplicationDbContext db,
            ClaimsPrincipal user,
            HttpContext ctx,
            string? status,
            string? search) =>
        {
            var role = await GetUserRole(db, user);
            IQueryable<Shipment> query = db.Shipments;

            if (role != "Dispatcher")
            {
                var email = user.FindFirstValue(ClaimTypes.Email) ?? user.FindFirstValue(ClaimTypes.Name);
                query = query.Where(s => s.CustomerEmail == email);
            }

            if (!string.IsNullOrEmpty(status) && Enum.TryParse<ShipmentStatus>(status, out var parsed))
                query = query.Where(s => s.Status == parsed);

            if (!string.IsNullOrEmpty(search))
                query = query.Where(s =>
                    s.TrackingNumber.Contains(search) ||
                    s.Destination.Contains(search) ||
                    s.RecipientName.Contains(search));

            return Results.Ok(await query.OrderByDescending(s => s.CreatedUtc).ToListAsync());
        });

        // Get single shipment
        api.MapGet("/{id:int}", async (int id, ApplicationDbContext db, ClaimsPrincipal user) =>
        {
            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();

            var role = await GetUserRole(db, user);
            if (role != "Dispatcher")
            {
                var email = user.FindFirstValue(ClaimTypes.Email) ?? user.FindFirstValue(ClaimTypes.Name);
                if (shipment.CustomerEmail != email) return Results.Forbid();
            }

            return Results.Ok(shipment);
        });

        // Track by tracking number (available to all authenticated users)
        api.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
        });

        // Dispatcher: update shipment status
        api.MapPut("/{id:int}/status", async (int id, StatusUpdate update, ApplicationDbContext db, ClaimsPrincipal user) =>
        {
            var role = await GetUserRole(db, user);
            if (role != "Dispatcher") return Results.Forbid();

            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();

            shipment.Status = update.Status;
            shipment.Notes = update.Notes ?? shipment.Notes;

            if (update.Status == ShipmentStatus.Delivered)
                shipment.ActualDeliveryUtc = DateTime.UtcNow;

            await db.SaveChangesAsync();
            return Results.Ok(shipment);
        });

        // Dispatcher: create new shipment
        api.MapPost("/", async (Shipment shipment, ApplicationDbContext db, ClaimsPrincipal user) =>
        {
            var role = await GetUserRole(db, user);
            if (role != "Dispatcher") return Results.Forbid();

            shipment.Id = 0;
            shipment.CreatedUtc = DateTime.UtcNow;
            shipment.TrackingNumber = $"TRK-{DateTime.UtcNow:yyyyMMdd}-{Guid.NewGuid().ToString()[..6].ToUpper()}";

            db.Shipments.Add(shipment);
            await db.SaveChangesAsync();
            return Results.Created($"/api/shipments/{shipment.Id}", shipment);
        });
    }

    private static async Task<string> GetUserRole(ApplicationDbContext db, ClaimsPrincipal user)
    {
        var userId = user.FindFirstValue(ClaimTypes.NameIdentifier);
        if (userId is null) return "Customer";
        var appUser = await db.Users.OfType<ApplicationUser>().FirstOrDefaultAsync(u => u.Id == userId);
        return appUser?.Role ?? "Customer";
    }
}

public record StatusUpdate(ShipmentStatus Status, string? Notes);

