@if (shipments is null)
{
    <p><em>Loading shipments…</em></p>
}
else if (shipments.Count == 0)
{
    <p>No shipments found.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Recipient</th>
                    <th>Status</th>
                    <th>Weight</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var s in shipments)
                {
                    <tr>
                        <td><strong>@s.TrackingNumber</strong></td>
                        <td>@s.Origin</td>
                        <td>@s.Destination</td>
                        <td>@s.RecipientName</td>
                        <td>
                            <span class="badge @GetStatusBadge(s.Status)">@s.Status</span>
                        </td>
                        <td>@s.WeightKg.ToString("F1") kg</td>
                        <td>@s.EstimatedDeliveryUtc.ToString("MMM dd, yyyy")</td>
                        <td>
                            @if (editingId == s.Id)
                            {
                                <div class="d-flex gap-1">
                                    <select class="form-select form-select-sm" style="width:auto" @bind="editStatus">
                                        @foreach (var st in Enum.GetValues<ShipmentStatus>())
                                        {
                                            <option value="@st">@st</option>
                                        }
                                    </select>
                                    <button class="btn btn-sm btn-success" @onclick="() => SaveStatus(s.Id)">Save</button>
                                    <button class="btn btn-sm btn-secondary" @onclick="() => editingId = null">✕</button>
                                </div>
                            }
                            else
                            {
                                <button class="btn btn-sm btn-outline-primary" @onclick="() => StartEdit(s)">
                                    Update
                                </button>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private List<Shipment>? shipments;
    private string searchText = "";
    private string statusFilter = "";
    private string? errorMessage;

    private bool showCreateForm;
    private bool creating;
    private Shipment newShipment = new();
    private DateTime estimatedDelivery = DateTime.Now.AddDays(5);

    private int? editingId;
    private ShipmentStatus editStatus;

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        try
        {
            errorMessage = null;
            var url = $"/api/shipments?status={statusFilter}&search={Uri.EscapeDataString(searchText)}";
            shipments = await Http.GetFromJsonAsync<List<Shipment>>(url);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load shipments: {ex.Message}";
        }
    }

    private async Task HandleSearch()
    {
        await LoadShipments();
    }

    private void StartEdit(Shipment s)
    {
        editingId = s.Id;
        editStatus = s.Status;
    }

    private async Task SaveStatus(int id)
    {
        try
        {
            var response = await Http.PutAsJsonAsync($"/api/shipments/{id}/status",
                new { Status = editStatus, Notes = (string?)null });

            if (response.IsSuccessStatusCode)
            {
                editingId = null;
                await LoadShipments();
            }
            else
            {
                errorMessage = "Failed to update status. You may not have dispatcher permissions.";
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Error: {ex.Message}";
        }
    }

    private async Task CreateShipment()
    {
        creating = true;
        try
        {
            newShipment.EstimatedDeliveryUtc = estimatedDelivery.ToUniversalTime();
            var response = await Http.PostAsJsonAsync("/api/shipments", newShipment);
            if (response.IsSuccessStatusCode)
            {
                newShipment = new();
                estimatedDelivery = DateTime.Now.AddDays(5);
                showCreateForm = false;
                await LoadShipments();
            }
            else
            {
                errorMessage = "Failed to create shipment. Ensure you have dispatcher permissions.";
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Error: {ex.Message}";
        }
        finally
        {
            creating = false;
        }
    }

    private static string GetStatusBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info text-dark",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Returned => "bg-dark",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

