    </div>
}

@code {
    private string trackingNumber = "";
    private bool tracking;
    private string? trackingError;
    private Shipment? trackedShipment;
    private List<Shipment>? myShipments;

    protected override async Task OnInitializedAsync()
    {
        await LoadMyShipments();
    }

    private async Task LoadMyShipments()
    {
        try
        {
            myShipments = await Http.GetFromJsonAsync<List<Shipment>>("/api/shipments");
        }
        catch
        {
            myShipments = new();
        }
    }

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        tracking = true;
        trackingError = null;
        trackedShipment = null;

        try
        {
            var response = await Http.GetAsync($"/api/shipments/track/{Uri.EscapeDataString(trackingNumber.Trim())}");
            if (response.IsSuccessStatusCode)
            {
                trackedShipment = await response.Content.ReadFromJsonAsync<Shipment>();
            }
            else
            {
                trackingError = $"No shipment found with tracking number \"{trackingNumber}\".";
            }
        }
        catch (Exception ex)
        {
            trackingError = $"Error looking up shipment: {ex.Message}";
        }
        finally
        {
            tracking = false;
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackShipment();
    }

    private void ViewDetails(string tn)
    {
        trackingNumber = tn;
        _ = TrackShipment();
    }

    private static bool IsOverdue(Shipment s) =>
        s.Status != ShipmentStatus.Delivered &&
        s.Status != ShipmentStatus.Cancelled &&
        s.EstimatedDeliveryUtc < DateTime.UtcNow;

    private static int GetProgress(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Returned => 100,
        ShipmentStatus.Cancelled => 100,
        _ => 0
    };

    private static string GetProgressColor(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        ShipmentStatus.Returned => "bg-dark",
        _ => "bg-primary"
    };

    private static string GetStatusBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info text-dark",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Returned => "bg-dark",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}
